```javascript
// 飞书云文档表格读取验证 - 直接在会话执行

try {
  // 1. 获取表格 blocks
  const blocksResp = await feishu_doc({
    action: "list_blocks",
    doc_token: "GaDhdogBhoQWRQx5lG4cpyQknUb"
  });

  const allBlocks = blocksResp.blocks || [];
  const blockMap = new Map(allBlocks.map(b => [b.block_id, b]));

  // 2. 定位表格 block
  const tableBlock = allBlocks.find(b => b.block_id === "doxcnwhyXhKB6ORGWeAHoW6vlJf" && b.block_type === 31);
  const cellIds = tableBlock.children || [];
  const columns = tableBlock.table.property.column_size; // 8

  console.log(`📊 表格结构:`);
  console.log(`   - 单元格数: ${cellIds.length}`);
  console.log(`   - 列数: ${columns}`);
  console.log(`   - 行数: ${Math.ceil(cellIds.length / columns)}`);
  console.log(`   - 元数据 row_size: ${tableBlock.table.row_size} (可能不准)`);
  console.log('');

  // 3. 提取单元格内容
  const getCellText = (cellBlock) => {
    if (!cellBlock || cellBlock.block_type !== 32 || !cellBlock.children) return '';
    let text = '';
    for (const tbId of cellBlock.children) {
      const tb = blockMap.get(tbId);
      if (tb && tb.block_type === 2 && tb.text?.elements) {
        const content = tb.text.elements.map(e => e.text_run?.content || '').join('');
        if (content) text += (text ? '\n' : '') + content;
      }
    }
    return text;
  };

  // 4. 构建二维数组
  const rows = [];
  for (let i = 0; i < cellIds.length; i += columns) {
    const row = cellIds.slice(i, i + columns).map(cid => getCellText(blockMap.get(cid)));
    rows.push(row);
  }

  console.log(`✅ 解析完成，共 ${rows.length} 行\n`);

  // 5. 显示表头
  console.log('表头 (Row 1):');
  console.log(rows[0].map((c, i) => `[${i}] "${c}"`).join(' | '));
  console.log('');

  // 6. 显示数据行
  const colNames = ['文件名', '文件类型', '本地路径', '备份时间', '文件大小', '文件哈希', '状态', '备注'];

  // 判断表头是否包含字段名
  const hasHeader = rows[0].some(c => colNames.some(name => c.includes(name)));

  console.log(hasHeader ? '📋 数据记录 (表头已识别):\n' : '📋 数据记录 (无表头，所有行均为数据):\n');

  const startIdx = hasHeader ? 1 : 0;
  for (let r = startIdx; r < rows.length; r++) {
    const row = rows[r];
    const rec = {};
    colNames.forEach((name, i) => rec[name] = row[i] || '');
    console.log(`  ${hasHeader ? `记录 ${r}` : `行 ${r}`}: ${rec.文件名} | ${rec.文件类型} | ${rec.本地路径} | ${rec.备份时间} | ${rec.文件大小} bytes | ${rec.文件哈希} | ${rec.状态}`);
  }

  console.log('\n✅ 验证成功：表格读取功能完全正常，数据结构清晰。');

} catch (error) {
  console.error('❌ 表格读取验证失败:', error);
}
